module RefModule (
    input wire a,
    input wire b,
    output wire hazard_detected,
    output wire resolved
);
  wire temp1_a = a;
  wire temp2_b = b;
  assign hazard_detected = temp1_a & temp2_b; // Hazard detected if both inputs are 1
    assign resolved = ~(a & b); // Hazard resolved if at least one input is 0
endmodule
